```plantuml
@startuml
class AbstractFactoryPatternDemo {
  void main()
}

class FactoryProducer {
  AbstractFactory getFactory()
}

abstract class AbstractFactory {
  Shape getShape()
  Color getColor()
}

class ShapeFactory {
  Shape getShape()
}

class ColorFactory {
  Color getColor()
}

package shape {
  interface Shape {
    void draw()
  }
  class Circle {
    void draw()
  }
  class Rectangle {
    void draw()
  }
  class Square {
    void draw()
  }
}

package color {
  interface Color {
    void fill()
  }
  class Blue {
    void fill()
  }
  class Green {
    void fill()
  }
  class Red {
    void fill()
  }
}

AbstractFactoryPatternDemo -> FactoryProducer : ask
FactoryProducer -> AbstractFactory : make

ShapeFactory -up-> AbstractFactory : extends
ColorFactory -up-> AbstractFactory : extends

ShapeFactory ---> Shape : create
ColorFactory ---> Color : create

Circle -up-> Shape : implement
Rectangle -up-> Shape : implement
Square -up-> Shape : implement

Blue -up-> Color : implement
Green -up-> Color : implement
Red -up-> Color : implement

@enduml
```
